const express = require('express');
const crypto = require('crypto');
const app = express();

const clients = new Map();
const authorizationCodes = new Map();
const tokens = new Map();

// Mock client registration
clients.set('client123', {
  clientId: 'client123',
  clientSecret: 'secret456',
  redirectUris: ['http://localhost:3000/callback']
});

// Generate secure random string
function generateRandomString(length) {
  return crypto.randomBytes(length).toString('hex');
}

// Generate authorization code
function generateAuthorizationCode() {
  return generateRandomString(32);
}

// Generate access token
function generateAccessToken() {
  return generateRandomString(40);
}

// Validate redirect URI
function validateRedirectUri(clientId, redirectUri) {
  const client = clients.get(clientId);
  if (!client) return false;
  return client.redirectUris.includes(redirectUri);
}

// Middleware to check if user is authenticated
function requireAuth(req, res, next) {
  if (req.session && req.session.user) {
    next();
  } else {
    res.redirect('/login');
  }
}

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;
  
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'Invalid response_type' });
  }
  
  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'Invalid redirect_uri' });
  }
  
  // Store authorization request for consent
  req.session.authRequest = {
    clientId: client_id,
    redirectUri: redirect_uri,
    scope,
    state
  };
  
  // Redirect to consent page
  res.redirect('/consent');
});

// Consent page
app.get('/consent', requireAuth, (req, res) => {
  const authRequest = req.session.authRequest;
  if (!authRequest) {
    return res.status(400).json({ error: 'No authorization request' });
  }
  
  res.send(`
    <form method="post" action="/consent/accept">
      <p>Do you authorize ${authRequest.clientId} to access your data?</p>
      <input type="hidden" name="state" value="${authRequest.state}">
      <button type="submit">Authorize</button>
    </form>
  `);
});

// Handle consent
app.post('/consent/accept', requireAuth, (req, res) => {
  const authRequest = req.session.authRequest;
  if (!authRequest) {
    return res.status(400).json({ error: 'No authorization request' });
  }
  
  const code = generateAuthorizationCode();
  authorizationCodes.set(code, {
    clientId: authRequest.clientId,
    redirectUri: authRequest.redirectUri,
    scope: authRequest.scope,
    userId: req.session.user.id,
    expiresAt: Date.now() + 300000 // 5 minutes
  });
  
  const redirectUri = `${authRequest.redirectUri}?code=${code}&state=${authRequest.state}`;
  res.redirect(redirectUri);
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;
  
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'Invalid grant_type' });
  }
  
  const authCode = authorizationCodes.get(code);
  if (!authCode) {
    return res.status(400).json({ error: 'Invalid authorization code' });
  }
  
  // Validate client credentials
  const client = clients.get(client_id);
  if (!client || client.clientSecret !== client_secret) {
    return res.status(401).json({ error: 'Invalid client credentials' });
  }
  
  // Validate redirect_uri
  if (authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'Invalid redirect_uri' });
  }
  
  // Check if code is expired
  if (authCode.expiresAt < Date.now()) {
    return res.status(400).json({ error: 'Authorization code expired' });
  }
  
  // Generate access token
  const accessToken = generateAccessToken();
  tokens.set(accessToken, {
    clientId: authCode.clientId,
    userId: authCode.userId,
    scope: authCode.scope,
    expiresAt: Date.now() + 3600000 // 1 hour
  });
  
  // Remove used authorization code
  authorizationCodes.delete(code);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

